import jsPDF from "jspdf";

export const downloadReport = (res) => {
  const doc = new jsPDF();

  doc.text("AI Health Report", 20, 20);
  doc.text(res.final_prediction.disease, 20, 40);
  doc.text(res.final_prediction.confidence + "%", 20, 50);

  doc.save("report.pdf");
};
